mapper.insert:
INSERT INTO [dbo].TB_FS_NOTI_ATTACH
     ( SYS_ID
     , NOTI_SEQ
     , ATCH_SEQ
     , ATCH_NM
     , ATCH_SIZE
     , ATCH_REF_ID
     , URL
     , ORG_FILE_NM
     , SER_FILE_NM
     , STATUS
     , RGSTR_ID
     , RGSTR_DT
     , MDFR_ID
     , MDFR_DT
     , SSMM)
VALUES
     ( #{sys_id}
     , #{noti_seq}
     , [dbo].FN_FS_GETSEQUENCE('TB_FS_NOTI_ATTACH_SEQ', #{sys_id}, #{noti_seq})
     , #{atch_nm}
     , #{atch_size}
     , #{atch_ref_id}
     , #{url}
     , #{org_file_nm}
     , #{ser_file_nm}
     , #{status}
     , #{rgstr_id}
     , GETDATE()
     , #{mdfr_id}
     , GETDATE()
     , #{ssmm})

mapper.update:
UPDATE [dbo].TB_FS_NOTI_MST
   SET TYPE_CD       = #{type_cd}
     , PRIORITY_CD   = #{priority_cd}
     , NOTI_TITLE    = #{noti_title}
     , NOTI_CONTENTS = #{noti_contents}
     , COMPLETE_DATE = #{complete_date}
     , MDFR_ID       = #{mdfr_id}
     , MDFR_DT       = GETDATE()
     , SSMM          = #{ssmm}
     , NOTI_CMM_YN   = #{noti_cmm_yn}
 WHERE 1=1
   AND SYS_ID        = #{sys_id}
   AND NOTI_SEQ      = #{noti_seq}

UPDATE [dbo].TB_FS_NOTI_ATTACH
   SET STATUS        = 'N'
     , MDFR_ID       = #{mdfr_id}
     , MDFR_DT       = GETDATE()
 WHERE 1=1
   AND SYS_ID        = #{sys_id}
   AND NOTI_SEQ      = #{noti_seq}

   AND ATCH_SEQ      = #{atch_seq}

UPDATE [dbo].TB_FS_NOTI_MST
   SET STATUS        = 'N'
     , MDFR_ID       = #{mdfr_id}
     , MDFR_DT       = GETDATE()
 WHERE 1=1
   AND SYS_ID        = #{sys_id}
   AND NOTI_SEQ      = #{noti_seq}
